    """Each task has required fields: task_id, prompt, canonical_solution, test, entry_point."""
    with HUMANEVAL_JSON.open() as f:
        tasks = json.load(f)
    required = {"task_id", "prompt", "canonical_solution", "test", "entry_point"}

for module in ("q_proj", "v_proj"):
